import React, { useState, useEffect } from 'react';
import api from '../api';
import { Patient, Doctor } from '../types'; // Import duha ka types

const AppointmentList: React.FC = () => {
  const [patients, setPatients] = useState<Patient[]>([]);
  const [doctors, setDoctors] = useState<Doctor[]>([]);
  const [selectedPatient, setSelectedPatient] = useState('');
  const [selectedDoctor, setSelectedDoctor] = useState('');
  const [date, setDate] = useState('');

  useEffect(() => {
    const loadData = async () => {
      const [pRes, dRes] = await Promise.all([api.get('patients/'), api.get('doctors/')]);
      setPatients(pRes.data);
      setDoctors(dRes.data);
    };
    loadData();
  }, []);

  const handleSchedule = async () => {
    try {
      const payload = {
        patient: parseInt(selectedPatient), // Kinahanglan Number/ID
        doctor: parseInt(selectedDoctor),   // Kinahanglan Number/ID
        appointment_date: date,
        status: 'Scheduled'
      };
      await api.post('appointments/', payload);
      alert("Appointment Booked!");
    } catch (err: any) {
      console.error("Payload Error:", err.response?.data);
    }
  };

  return (
    <div className="p-4 space-y-4 border rounded">
      <select onChange={e => setSelectedPatient(e.target.value)}>
        <option value="">Select Patient</option>
        {patients.map(p => <option key={p.patient_id} value={p.patient_id}>{p.first_name}</option>)}
      </select>
      <select onChange={e => setSelectedDoctor(e.target.value)}>
        <option value="">Select Doctor</option>
        {doctors.map(d => <option key={d.doctor_id} value={d.doctor_id}>Dr. {d.last_name}</option>)}
      </select>
      <input type="datetime-local" onChange={e => setDate(e.target.value)} />
      <button onClick={handleSchedule} className="bg-blue-600 text-white p-2 rounded">Submit</button>
    </div>
  );
};
export default AppointmentList;
